using Store;

namespace ShoppingCart.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private Store.ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new Store.ShoppingCart();
    }

    // --- AddItem ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem("SKU-001", quantity, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem("SKU-001", 1, -1.00m));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem(sku!, 1, 5.00m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonexistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveItem("NONEXISTENT"));
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_LeavesOthers()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 1, 20.00m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _sut.AddItem("SKU-001", 2, 15.00m);
        _sut.AddItem("SKU-002", 1, 7.50m);
        _sut.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _sut.AddItem("SKU-001", 1, 100.00m);
        _sut.ApplyCoupon("SAVE10");

        var total = _sut.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total but got {total}");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        _sut.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.ApplyCoupon("INVALIDCODE"));
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.ApplyCoupon("SAVE10"));
    }
}

